                </div>
            </div>
            <div className="p-4 border-t border-slate-200 bg-white">
                <NexButton variant="primary" onClick={handleSimulate} disabled={!ruleId || isRunning} className="w-full" icon={Play}>Run Simulation</NexButton>
            </div>
        </div>
    );
