export const TaskInbox: React.FC = () => {
  const { tasks, completeTask, addTaskComment, currentUser, delegations, navigateTo, openInstanceViewer } = useBPM();
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [commentText, setCommentText] = useState('');

  const delegateRules = delegations.filter(d => d.toUserId === currentUser?.id && d.isActive);
  const myTasks = tasks.filter(t => t.assignee === currentUser?.id);
  const delegatedTasks = tasks.filter(t => delegateRules.some(d => d.fromUserId === t.assignee));
  const unassignedTasks = tasks.filter(t => t.status === TaskStatus.PENDING && t.assignee === 'Unassigned');

  const handleAction = async (id: string, action: 'approve' | 'reject') => {
    await completeTask(id, action, action === 'approve' ? 'Approved' : 'Rejected');
    setSelectedTask(null);
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-white border border-slate-300 rounded-sm shadow-sm overflow-hidden">
      {/* Master List */}
      <div className={`w-full lg:w-80 flex flex-col border-r border-slate-200 bg-white ${selectedTask ? 'hidden lg:flex' : 'flex'}`}>
        <div className="p-3 border-b border-slate-200 bg-slate-50">
           <div className="relative">
             <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"/>
             <input className="w-full pl-8 pr-3 py-1.5 text-xs border border-slate-300 rounded-sm focus:ring-1 focus:ring-blue-500 outline-none" placeholder="Filter tasks..." />
           </div>
        </div>
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-slate-500 uppercase border-y border-slate-200">My Worklist ({myTasks.length})</div>
          {myTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} onClick={setSelectedTask} />)}

          {delegatedTasks.length > 0 && (
            <>
              <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-blue-600 uppercase border-y border-slate-200 flex items-center gap-2"><ShieldAlert size={10}/> Delegated</div>
              {delegatedTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} onClick={setSelectedTask} />)}
            </>
          )}

          <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-slate-500 uppercase border-y border-slate-200">Unassigned ({unassignedTasks.length})</div>
          {unassignedTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} onClick={setSelectedTask} />)}
        </div>
      </div>

      {/* Detail View */}
      <div className={`flex-1 flex flex-col bg-slate-50 ${selectedTask ? 'flex' : 'hidden lg:flex'}`}>
        {selectedTask ? (
          <>
            <div className="h-14 border-b border-slate-200 bg-white flex items-center justify-between px-6 shadow-sm z-10">
              <div className="flex items-center gap-3">
                <button onClick={() => setSelectedTask(null)} className="lg:hidden p-1 border rounded hover:bg-slate-100"><ChevronLeft size={16}/></button>
                <div className="flex flex-col">
                  <span className="text-[10px] font-mono text-slate-400">{selectedTask.id}</span>
                  <h2 className="text-sm font-bold text-slate-800">{selectedTask.title}</h2>
                </div>
              </div>
              <div className="flex gap-2">
                <NexButton variant="secondary" onClick={() => openInstanceViewer(selectedTask.processInstanceId)} icon={Layers}>Diagram</NexButton>
                {selectedTask.caseId && <NexButton variant="secondary" onClick={() => navigateTo('case-viewer', selectedTask.caseId)} icon={Briefcase}>Case</NexButton>}
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
               <div className="bg-white border border-slate-300 rounded-sm p-6 mb-6 shadow-sm">
                  <h3 className="text-xs font-bold text-slate-700 uppercase border-b border-slate-100 pb-2 mb-4">Task Context</h3>
                  <p className="text-sm text-slate-700 leading-relaxed mb-6">{selectedTask.description || "No specific instructions provided for this task."}</p>

                  <div className="grid grid-cols-2 gap-4 text-xs">
                    <div><span className="text-slate-500 block mb-1">Process</span> <span className="font-medium">{selectedTask.processName}</span></div>
                    <div><span className="text-slate-500 block mb-1">Priority</span> <NexBadge variant={selectedTask.priority === 'Critical' ? 'rose' : 'blue'}>{selectedTask.priority}</NexBadge></div>
                    <div><span className="text-slate-500 block mb-1">Due Date</span> <span className="font-medium">{new Date(selectedTask.dueDate).toLocaleDateString()}</span></div>
                    <div><span className="text-slate-500 block mb-1">Assignee</span> <span className="font-medium">{selectedTask.assignee}</span></div>
                  </div>
               </div>

               <div className="bg-white border border-slate-300 rounded-sm p-6 shadow-sm">
                  <h3 className="text-xs font-bold text-slate-700 uppercase border-b border-slate-100 pb-2 mb-4">Activity Log</h3>
                  <NexHistoryFeed history={selectedTask.comments} />
                  <div className="mt-4 pt-4 border-t border-slate-100 flex gap-2">
                     <input className="prop-input" placeholder="Add comment..." value={commentText} onChange={e => setCommentText(e.target.value)} />
                     <NexButton onClick={() => { if(selectedTask && commentText) { addTaskComment(selectedTask.id, commentText); setCommentText(''); }}} icon={Send}>Add</NexButton>
                  </div>
               </div>
            </div>

            <div className="p-4 border-t border-slate-300 bg-white flex justify-end gap-3">
              <NexButton variant="danger" onClick={() => handleAction(selectedTask.id, 'reject')}>Reject</NexButton>
              <NexButton variant="primary" onClick={() => handleAction(selectedTask.id, 'approve')}>Approve & Complete</NexButton>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <CheckSquare size={48} className="mb-4 opacity-20"/>
            <p className="text-sm font-medium">Select a task item to view details</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  ArrowLeft, Users, Send, Settings, Activity, 
  CheckSquare, ChevronRight, Briefcase, ShieldCheck, Play, X, Layers
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexCard } from './shared/NexUI';

export const CaseViewer: React.FC<{ caseId: string }> = ({ caseId }) => {
  const { cases, tasks, processes, navigateTo, addCaseEvent, currentUser, openInstanceViewer, startProcess } = useBPM();
  const [activeTab, setActiveTab] = useState<'timeline' | 'tasks' | 'data' | 'content'>('timeline');
  const [note, setNote] = useState('');
  const [showLaunchModal, setShowLaunchModal] = useState(false);

  const currentCase = cases.find(c => c.id === caseId);
  const relatedTasks = useMemo(() => tasks.filter(t => t.caseId === caseId), [tasks, caseId]);

  if (!currentCase) return <div className="p-20 text-center text-slate-400">Case file not found.</div>;

  const handlePostNote = async (e: React.SyntheticEvent) => {
    e.preventDefault();
    if (!note.trim()) return;
    await addCaseEvent(caseId, note);
    setNote('');
  };

  const handleLaunchWorkflow = async (procId: string) => {
    await startProcess(procId, { summary: `Auto-launched from case: ${currentCase.title}` }, caseId);
    setShowLaunchModal(false);
    setActiveTab('tasks');
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] animate-fade-in bg-white rounded-sm border border-slate-300 shadow-sm overflow-hidden relative">
      <header className="h-14 px-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
        <div className="flex items-center gap-3">
          <button onClick={() => navigateTo('cases')} className="p-1 hover:bg-white border border-transparent hover:border-slate-200 rounded-sm transition-all"><ArrowLeft size={16}/></button>
          <div className="h-6 w-px bg-slate-300 mx-1"></div>
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-sm font-bold text-slate-800">{currentCase.title}</h2>
              <NexBadge variant="blue">{currentCase.status}</NexBadge>
            </div>
            <p className="text-[10px] text-slate-400 font-mono">{currentCase.id}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <NexButton variant="secondary" icon={Play} onClick={() => setShowLaunchModal(true)}>Action</NexButton>
           <NexButton variant="primary" onClick={() => {}}>Close</NexButton>
        </div>
      </header>

      {showLaunchModal && (
        <div className="absolute inset-0 z-50 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-md rounded-sm border border-slate-300 p-6 shadow-xl animate-slide-up space-y-4">
              <div className="flex justify-between items-center">
                 <h3 className="text-lg font-bold text-slate-900">Select Blueprint</h3>
                 <button onClick={() => setShowLaunchModal(false)} className="p-1 text-slate-400 hover:text-slate-600"><X size={18}/></button>
              </div>
              <div className="space-y-2 max-h-80 overflow-y-auto border-t border-b border-slate-100 py-2">
                 {processes.map(proc => (
                   <button 
                     key={proc.id} 
                     onClick={() => handleLaunchWorkflow(proc.id)}
                     className="w-full p-3 border border-slate-200 rounded-sm flex items-center justify-between hover:border-blue-400 hover:bg-blue-50 transition-all text-left group"
                   >
                     <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-sm bg-slate-100 flex items-center justify-center text-slate-500 group-hover:bg-blue-600 group-hover:text-white transition-all"><Layers size={16}/></div>
                        <span className="font-bold text-xs text-slate-800">{proc.name}</span>
                     </div>
                     <ChevronRight size={14} className="text-slate-300 group-hover:text-blue-600" />
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      <div className="flex-1 flex overflow-hidden">
        <aside className="w-64 border-r border-slate-200 flex flex-col hidden xl:flex p-4 bg-slate-50 space-y-6">
           <div>
              <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-2">Stakeholders</h4>
              <div className="flex flex-wrap gap-2">
                 {[1,2,3].map(i => <div key={i} className="w-8 h-8 rounded-sm bg-white border border-slate-300 flex items-center justify-center font-bold text-xs text-slate-700">U{i}</div>)}
              </div>
           </div>
           <div className="space-y-3 pt-3 border-t border-slate-200">
              <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Metadata</h4>
              <div className="space-y-1">
                 <div className="flex justify-between text-xs"><span className="text-slate-500">Created</span><span className="font-medium text-slate-800">{new Date(currentCase.createdAt).toLocaleDateString()}</span></div>
                 <div className="flex justify-between text-xs"><span className="text-slate-500">Domain</span><span className="font-medium text-slate-800">{currentCase.domainId}</span></div>
              </div>
           </div>
        </aside>

        <main className="flex-1 flex flex-col bg-white">
           <div className="flex border-b border-slate-200 bg-white">
              {['timeline', 'tasks', 'data', 'content'].map(tab => (
                <button 
                  key={tab} 
                  onClick={() => setActiveTab(tab as any)} 
                  className={`px-6 py-3 text-xs font-bold uppercase tracking-wider transition-all border-b-2 ${activeTab === tab ? 'text-blue-600 border-blue-600' : 'text-slate-500 border-transparent hover:text-slate-800'}`}
                >
                  {tab}
                </button>
              ))}
           </div>

           <div className="flex-1 overflow-y-auto p-6 bg-slate-50">
              {activeTab === 'timeline' && (
                <div className="max-w-2xl mx-auto space-y-6">
                   <div className="bg-white p-4 rounded-sm border border-slate-300 shadow-sm">
                      <div className="flex gap-3 mb-3">
                         <div className="w-8 h-8 rounded-sm bg-blue-100 border border-blue-200 flex items-center justify-center text-blue-700 font-bold shrink-0 text-xs">{currentUser?.name[0]}</div>
                         <textarea className="flex-1 bg-transparent outline-none text-xs min-h-[60px] resize-none" placeholder="Post a case note..." value={note} onChange={e => setNote(e.target.value)} />
                      </div>
                      <div className="flex justify-end">
                         <NexButton variant="primary" onClick={handlePostNote} icon={Send}>Post</NexButton>
                      </div>
                   </div>
                   <NexHistoryFeed history={currentCase.timeline} />
                </div>
              )}

              {activeTab === 'tasks' && (
                <div className="max-w-3xl mx-auto space-y-3">
                  {relatedTasks.map(task => {
                    return (
                      <div key={task.id} className="bg-white p-4 rounded-sm border border-slate-300 shadow-sm flex items-center justify-between group hover:border-blue-400 transition-all">
                        <div className="flex items-center gap-4">
                          <div className="w-8 h-8 rounded-sm flex items-center justify-center bg-slate-100 text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600 transition-all border border-slate-200">
                            <CheckSquare size={16} />
                          </div>
                          <div>
                            <h4 className="text-sm font-bold text-slate-900">{task.title}</h4>
                            <div className="flex items-center gap-2 mt-0.5">
                              <NexBadge variant={task.priority === 'Critical' ? 'rose' : 'blue'}>{task.priority}</NexBadge>
                              <span className="text-[10px] text-slate-400 font-bold uppercase">{task.status}</span>
                            </div>
                          </div>
                        </div>
                        <div className="flex gap-2">
                          <NexButton variant="secondary" onClick={() => openInstanceViewer(task.processInstanceId)} icon={Activity} />
                          <NexButton variant="primary" onClick={() => navigateTo('inbox', task.id)} icon={ChevronRight} />
                        </div>
                      </div>
                    );
                  })}
                  {relatedTasks.length === 0 && (
                    <div className="p-12 text-center text-slate-400 italic text-xs">No tasks associated with this case.</div>
                  )}
                </div>
              )}
           </div>
        </main>
      </div>
    </div>
  );
};

