import { useBPM } from '../contexts/BPMContext';
import { 
  Search, CheckSquare, ShieldAlert, ChevronLeft, 
  Briefcase, Send, Layers, Clock, AlertCircle, UserPlus, Settings, Tag
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexModal, NexFormGroup } from './shared/NexUI';

interface ListItemProps {
  task: Task;
  isSelected: boolean;
  onClick: (task: Task) => void;
}

const ListItem: React.FC<ListItemProps> = ({ task, isSelected, onClick }) => {
  return (
    <div 
      onClick={() => onClick(task)}
      className={`px-4 py-3 border-b border-slate-200 cursor-pointer hover:bg-slate-50 transition-colors group ${isSelected ? 'bg-blue-50 border-l-4 border-l-blue-600 pl-3' : 'border-l-4 border-l-transparent pl-3'}`}
    >
      <div className="flex justify-between items-start mb-1">
        <span className={`text-[13px] font-bold truncate pr-2 ${isSelected ? 'text-blue-800' : 'text-slate-800'}`}>{task.title}</span>
        {task.priority === TaskPriority.CRITICAL && <AlertCircle size={14} className="text-rose-600 shrink-0"/>}
      </div>
      <div className="flex justify-between items-center text-[11px] text-slate-500">
        <span className="truncate max-w-[120px]">{task.processName}</span>
        <span>{new Date(task.dueDate).toLocaleDateString()}</span>
      </div>
    </div>
  );
};

export const TaskInbox: React.FC = () => {
  const { tasks, completeTask, addTaskComment, reassignTask, updateTaskMetadata, currentUser, delegations, users, navigateTo, openInstanceViewer } = useBPM();
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [commentText, setCommentText] = useState('');

  // Modal States
  const [showReassign, setShowReassign] = useState(false);
  const [reassignTarget, setReassignTarget] = useState('');
  const [showMetadata, setShowMetadata] = useState(false);

  // Metadata Form State
  const [metaPriority, setMetaPriority] = useState<TaskPriority>(TaskPriority.MEDIUM);
  const [metaDueDate, setMetaDueDate] = useState('');

  const delegateRules = delegations.filter(d => d.toUserId === currentUser?.id && d.isActive);
  const myTasks = tasks.filter(t => t.assignee === currentUser?.id);
  const delegatedTasks = tasks.filter(t => delegateRules.some(d => d.fromUserId === t.assignee));
  const unassignedTasks = tasks.filter(t => t.status === TaskStatus.PENDING && t.assignee === 'Unassigned');

  const handleAction = async (id: string, action: 'approve' | 'reject') => {
    await completeTask(id, action, action === 'approve' ? 'Approved' : 'Rejected');
    setSelectedTask(null);
  };

  const openReassign = () => {
      setReassignTarget('');
      setShowReassign(true);
  };

  const handleReassign = async () => {
      if (selectedTask && reassignTarget) {
          await reassignTask(selectedTask.id, reassignTarget);
          setShowReassign(false);
          setSelectedTask(null); // Deselect as it might move out of "My Tasks"
      }
  };

  const openMetadata = () => {
      if (selectedTask) {
          setMetaPriority(selectedTask.priority);
          setMetaDueDate(selectedTask.dueDate.split('T')[0]);
          setShowMetadata(true);
      }
  };

  const handleUpdateMetadata = async () => {
      if (selectedTask) {
          await updateTaskMetadata(selectedTask.id, {
              priority: metaPriority,
              dueDate: new Date(metaDueDate).toISOString()
          });
          setShowMetadata(false);
          // Optimistically update local state if needed, or rely on context reload
      }
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-white border border-slate-300 rounded-sm shadow-sm overflow-hidden">

      {/* --- Modals --- */}
      <NexModal isOpen={showReassign} onClose={() => setShowReassign(false)} title="Transfer Ownership">
          <div className="space-y-4">
              <NexFormGroup label="New Owner">
                  <select className="prop-input" value={reassignTarget} onChange={e => setReassignTarget(e.target.value)}>
                      <option value="">Select Principal...</option>
                      {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                  </select>
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleReassign} icon={UserPlus}>Confirm Transfer</NexButton>
              </div>
          </div>
      </NexModal>

      <NexModal isOpen={showMetadata} onClose={() => setShowMetadata(false)} title="Task Parameters">
          <div className="space-y-4">
              <NexFormGroup label="Priority Level">
                  <select className="prop-input" value={metaPriority} onChange={e => setMetaPriority(e.target.value as TaskPriority)}>
                      {Object.values(TaskPriority).map(p => <option key={p} value={p}>{p}</option>)}
                  </select>
              </NexFormGroup>
              <NexFormGroup label="Due Date">
                  <input type="date" className="prop-input" value={metaDueDate} onChange={e => setMetaDueDate(e.target.value)} />
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleUpdateMetadata} icon={Settings}>Update Task</NexButton>
              </div>
          </div>
      </NexModal>

      {/* Master List */}
      <div className={`w-full lg:w-80 flex flex-col border-r border-slate-200 bg-white ${selectedTask ? 'hidden lg:flex' : 'flex'}`}>
        <div className="p-3 border-b border-slate-200 bg-slate-50">
           <div className="relative">
             <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"/>
             <input className="w-full pl-8 pr-3 py-1.5 text-xs border border-slate-300 rounded-sm focus:ring-1 focus:ring-blue-500 outline-none" placeholder="Filter tasks..." />
           </div>
        </div>
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-slate-500 uppercase border-y border-slate-200">My Worklist ({myTasks.length})</div>
          {myTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} onClick={setSelectedTask} />)}

          {delegatedTasks.length > 0 && (
            <>
              <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-blue-600 uppercase border-y border-slate-200 flex items-center gap-2"><ShieldAlert size={10}/> Delegated</div>
              {delegatedTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} onClick={setSelectedTask} />)}
            </>
          )}

          <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-slate-500 uppercase border-y border-slate-200">Unassigned ({unassignedTasks.length})</div>
          {unassignedTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} onClick={setSelectedTask} />)}
        </div>
      </div>

      {/* Detail View */}
      <div className={`flex-1 flex flex-col bg-slate-50 ${selectedTask ? 'flex' : 'hidden lg:flex'}`}>
        {selectedTask ? (
          <>
            <div className="h-14 border-b border-slate-200 bg-white flex items-center justify-between px-6 shadow-sm z-10">
              <div className="flex items-center gap-3">
                <button onClick={() => setSelectedTask(null)} className="lg:hidden p-1 border rounded hover:bg-slate-100"><ChevronLeft size={16}/></button>
                <div className="flex flex-col">
                  <span className="text-[10px] font-mono text-slate-400">{selectedTask.id}</span>
                  <h2 className="text-sm font-bold text-slate-800">{selectedTask.title}</h2>
                </div>
              </div>
              <div className="flex gap-2">
                <NexButton variant="secondary" onClick={openReassign} icon={UserPlus}>Reassign</NexButton>
                <NexButton variant="secondary" onClick={openMetadata} icon={Settings}>Metadata</NexButton>
                <div className="h-6 w-px bg-slate-300 mx-2"></div>
                <NexButton variant="secondary" onClick={() => openInstanceViewer(selectedTask.processInstanceId)} icon={Layers}>Diagram</NexButton>
                {selectedTask.caseId && <NexButton variant="secondary" onClick={() => navigateTo('case-viewer', selectedTask.caseId)} icon={Briefcase}>Case</NexButton>}
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
               <div className="bg-white border border-slate-300 rounded-sm p-6 mb-6 shadow-sm">
                  <div className="flex justify-between items-start mb-4 border-b border-slate-100 pb-2">
                      <h3 className="text-xs font-bold text-slate-700 uppercase">Task Context</h3>
                      {selectedTask.isAdHoc && <NexBadge variant="amber">Ad-Hoc</NexBadge>}
                  </div>
                  <p className="text-sm text-slate-700 leading-relaxed mb-6">{selectedTask.description || "No specific instructions provided for this task."}</p>

                  <div className="grid grid-cols-2 gap-4 text-xs">
                    <div><span className="text-slate-500 block mb-1">Process</span> <span className="font-medium">{selectedTask.processName}</span></div>
                    <div><span className="text-slate-500 block mb-1">Priority</span> <NexBadge variant={selectedTask.priority === 'Critical' ? 'rose' : 'blue'}>{selectedTask.priority}</NexBadge></div>
                    <div><span className="text-slate-500 block mb-1">Due Date</span> <span className="font-medium">{new Date(selectedTask.dueDate).toLocaleDateString()}</span></div>
                    <div><span className="text-slate-500 block mb-1">Assignee</span> <span className="font-medium">{selectedTask.assignee}</span></div>
                  </div>
               </div>

               <div className="bg-white border border-slate-300 rounded-sm p-6 shadow-sm">
                  <h3 className="text-xs font-bold text-slate-700 uppercase border-b border-slate-100 pb-2 mb-4">Activity Log</h3>
                  <NexHistoryFeed history={selectedTask.comments} />
                  <div className="mt-4 pt-4 border-t border-slate-100 flex gap-2">
                     <input className="prop-input" placeholder="Add comment..." value={commentText} onChange={e => setCommentText(e.target.value)} />
                     <NexButton onClick={() => { if(selectedTask && commentText) { addTaskComment(selectedTask.id, commentText); setCommentText(''); }}} icon={Send}>Add</NexButton>
                  </div>
               </div>
            </div>

            <div className="p-4 border-t border-slate-300 bg-white flex justify-end gap-3">
              <NexButton variant="danger" onClick={() => handleAction(selectedTask.id, 'reject')}>Reject</NexButton>
              <NexButton variant="primary" onClick={() => handleAction(selectedTask.id, 'approve')}>Approve & Complete</NexButton>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <CheckSquare size={48} className="mb-4 opacity-20"/>
            <p className="text-sm font-medium">Select a task item to view details</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ProcessStep, UserRole } from '../../types';
import { useBPM } from '../../contexts/BPMContext';
import { MousePointer2, Trash2, Info, UserCheck, Cpu, Compass, X, ChevronDown, FunctionSquare, ExternalLink, Globe, Key, Clock, Code } from 'lucide-react';
import { NexButton, NexFormGroup } from '../shared/NexUI';

export const PropertiesPanel = ({ 
  step, 
  onUpdate, 
  onDelete, 
  roles 
}: { 
  step: ProcessStep | undefined; 
  onUpdate: (step: ProcessStep) => void; 
  onDelete: (id: string) => void; 
  roles: UserRole[]; 
}) => {
    const { rules, decisionTables, navigateTo } = useBPM();
    const [activeSection, setActiveSection] = useState('general');

    if (!step) {
      return (
        <aside className="hidden md:flex w-full h-full flex-col items-center justify-center text-center p-8 bg-white border-l border-slate-300">
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 border border-slate-200">
            <Compass size={32} strokeWidth={1} className="text-slate-300" />
          </div>
          <h3 className="text-sm font-bold text-slate-800">Inspector</h3>
          <p className="text-xs text-slate-500 mt-2 max-w-[200px]">Select a component to configure properties.</p>
        </aside>
      );
    }

    const updateField = (field: keyof ProcessStep, value: any) => { onUpdate({ ...step, [field]: value }); };
    const updateDataField = (key: string, value: any) => { onUpdate({ ...step, data: { ...step.data, [key]: value } }); };
    const toggleSkill = (skill: string) => {
        const skills = step.requiredSkills || [];
        const newSkills = skills.includes(skill) ? skills.filter(sk => sk !== skill) : [...skills, skill];
        onUpdate({ ...step, requiredSkills: newSkills });
    };

    return (
      <aside className="w-full h-full bg-white border-l border-slate-300 flex flex-col shadow-xl z-20">
        <div className="h-10 flex items-center justify-between px-4 border-b border-slate-300 bg-slate-50">
          <div className="flex items-center gap-2">
            <h3 className="text-xs font-bold text-slate-800 uppercase tracking-wider">Properties</h3>
            <span className="text-[10px] text-slate-400 font-mono">| {step.type}</span>
          </div>
          <button onClick={() => onUpdate({ ...step, id: step.id } as any)} className="text-slate-400 hover:text-slate-800"><X size={16}/></button>
        </div>

        <div className="flex-1 p-4 space-y-6 overflow-y-auto no-scrollbar">

          {/* General Metadata Section */}
          <section className="space-y-4">
            <h4 className="text-xs font-bold text-slate-800 border-b border-slate-100 pb-2">General</h4>
            <NexFormGroup label="Identity">
              <input 
                type="text" 
                className="prop-input" 
                value={step.name} 
                onChange={e => updateField('name', e.target.value)} 
              />
            </NexFormGroup>
            <NexFormGroup label="Documentation">
              <textarea 
                className="prop-input h-20 resize-none"
                value={step.description} 
                onChange={e => updateField('description', e.target.value)} 
              />
            </NexFormGroup>
          </section>

          {/* Conditional Sections based on Node Type */}

          {step.type === 'service-task' && (
              <section className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-800 border-b border-slate-100 pb-2 flex items-center gap-2"><Globe size={12}/> REST Integration</h4>
                  <NexFormGroup label="Endpoint URL">
                      <input className="prop-input font-mono" placeholder="https://api.internal/..." value={step.data?.url || ''} onChange={e => updateDataField('url', e.target.value)} />
                  </NexFormGroup>
                  <div className="grid grid-cols-2 gap-4">
                      <NexFormGroup label="Method">
                          <select className="prop-input" value={step.data?.method || 'GET'} onChange={e => updateDataField('method', e.target.value)}>
                              <option>GET</option><option>POST</option><option>PUT</option><option>DELETE</option>
                          </select>
                      </NexFormGroup>
                      <NexFormGroup label="Auth Mode">
                          <select className="prop-input" value={step.data?.auth || 'None'} onChange={e => updateDataField('auth', e.target.value)}>
                              <option>None</option><option>Basic</option><option>Bearer Token</option>
                          </select>
                      </NexFormGroup>
                  </div>
              </section>
          )}

          {step.type === 'user-task' && (
              <section className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-800 border-b border-slate-100 pb-2 flex items-center gap-2"><UserCheck size={12}/> Assignment</h4>
                  <NexFormGroup label="Role Assignment">
                    <select 
                      className="prop-input appearance-none" 
                      value={step.role || ''} 
                      onChange={e => updateField('role', e.target.value)}
                    >
                      <option value="">Unassigned</option>
                      {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </select>
                  </NexFormGroup>
                  <NexFormGroup label="SLA Deadline">
                      <div className="flex gap-2">
                          <input type="number" className="prop-input w-20" value={step.data?.slaValue || 2} onChange={e => updateDataField('slaValue', e.target.value)} />
                          <select className="prop-input flex-1" value={step.data?.slaUnit || 'Days'} onChange={e => updateDataField('slaUnit', e.target.value)}>
                              <option>Hours</option><option>Days</option><option>Weeks</option>
                          </select>
                      </div>
                  </NexFormGroup>
                  <NexFormGroup label="Required Skills">
                    <div className="flex flex-wrap gap-1.5 pt-1">
                      {['BPMN', 'Leadership', 'Accounting', 'Logistics', 'Audit'].map(skill => (
                        <button 
                          key={skill} 
                          onClick={() => toggleSkill(skill)} 
                          className={`px-2 py-1 rounded-sm text-[10px] font-bold uppercase border transition-all ${
                            step.requiredSkills?.includes(skill) 
                              ? 'bg-slate-800 text-white border-slate-800' 
                              : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                          }`}
                        >
                          {skill}
                        </button>
                      ))}
                    </div>
                  </NexFormGroup>
              </section>
          )}

          {step.type === 'rules-engine-task' && (
              <section className="space-y-4">
                <div className="flex items-center justify-between border-b border-slate-100 pb-2">
                   <h4 className="text-xs font-bold text-slate-800 flex items-center gap-2"><FunctionSquare size={12}/> Logic Binding</h4>
                   {step.data?.ruleId && (
                    <button onClick={() => navigateTo('rules', step.data.ruleId)} className="text-[10px] text-blue-600 hover:underline flex items-center gap-1">Open <ExternalLink size={10}/></button>
                   )}
                </div>
                <NexFormGroup label="Rule Set">
                  <select 
                    className="prop-input appearance-none" 
                    value={step.data?.ruleId || ''} 
                    onChange={e => updateDataField('ruleId', e.target.value)}
                  >
                    <option value="">Select Asset...</option>
                    <optgroup label="Rules">
                        {rules.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </optgroup>
                    <optgroup label="Tables">
                        {decisionTables.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </optgroup>
                  </select>
                </NexFormGroup>
              </section>
          )}
        </div>

        <div className="p-4 border-t border-slate-200 bg-slate-50">
          <NexButton variant="danger" onClick={() => onDelete(step.id)} className="w-full" icon={Trash2}>Delete Component</NexButton>
        </div>
      </aside>
    );
};

import React, { useState, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  ArrowLeft, Users, Send, Settings, Activity, 
  CheckSquare, ChevronRight, Briefcase, ShieldCheck, Play, X, Layers, Plus, Shield
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexCard, NexModal, NexFormGroup } from './shared/NexUI';

export const CaseViewer: React.FC<{ caseId: string }> = ({ caseId }) => {
  const { cases, tasks, processes, users, navigateTo, addCaseEvent, addCasePolicy, addCaseStakeholder, currentUser, openInstanceViewer, startProcess } = useBPM();
  const [activeTab, setActiveTab] = useState<'timeline' | 'tasks' | 'data' | 'content'>('timeline');
  const [note, setNote] = useState('');

  // Modals
  const [showLaunchModal, setShowLaunchModal] = useState(false);
  const [showPolicyModal, setShowPolicyModal] = useState(false);
  const [showStakeholderModal, setShowStakeholderModal] = useState(false);

  // Forms
  const [newPolicy, setNewPolicy] = useState('');
  const [newStakeholderId, setNewStakeholderId] = useState('');
  const [newStakeholderRole, setNewStakeholderRole] = useState('Consultant');

  const currentCase = cases.find(c => c.id === caseId);
  const relatedTasks = useMemo(() => tasks.filter(t => t.caseId === caseId), [tasks, caseId]);

  if (!currentCase) return <div className="p-20 text-center text-slate-400">Case file not found.</div>;

  const handlePostNote = async (e: React.SyntheticEvent) => {
    e.preventDefault();
    if (!note.trim()) return;
    await addCaseEvent(caseId, note);
    setNote('');
  };

  const handleLaunchWorkflow = async (procId: string) => {
    await startProcess(procId, { summary: `Auto-launched from case: ${currentCase.title}` }, caseId);
    setShowLaunchModal(false);
    setActiveTab('tasks');
  };

  const handleAddPolicy = async () => {
      if (newPolicy) {
          await addCasePolicy(caseId, newPolicy);
          setShowPolicyModal(false);
          setNewPolicy('');
      }
  };

  const handleAddStakeholder = async () => {
      if (newStakeholderId) {
          await addCaseStakeholder(caseId, newStakeholderId, newStakeholderRole);
          setShowStakeholderModal(false);
          setNewStakeholderId('');
      }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] animate-fade-in bg-white rounded-sm border border-slate-300 shadow-sm overflow-hidden relative">
      <header className="h-14 px-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
        <div className="flex items-center gap-3">
          <button onClick={() => navigateTo('cases')} className="p-1 hover:bg-white border border-transparent hover:border-slate-200 rounded-sm transition-all"><ArrowLeft size={16}/></button>
          <div className="h-6 w-px bg-slate-300 mx-1"></div>
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-sm font-bold text-slate-800">{currentCase.title}</h2>
              <NexBadge variant="blue">{currentCase.status}</NexBadge>
            </div>
            <p className="text-[10px] text-slate-400 font-mono">{currentCase.id}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <NexButton variant="secondary" icon={Play} onClick={() => setShowLaunchModal(true)}>Action</NexButton>
           <NexButton variant="primary" onClick={() => {}}>Close</NexButton>
        </div>
      </header>

      {/* --- Modals --- */}
      <NexModal isOpen={showPolicyModal} onClose={() => setShowPolicyModal(false)} title="Attach Policy">
          <div className="space-y-4">
              <NexFormGroup label="Policy Statement">
                  <textarea className="prop-input h-32 resize-none" value={newPolicy} onChange={e => setNewPolicy(e.target.value)} placeholder="e.g. All refunds > $500 must have VP approval..." />
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleAddPolicy} icon={ShieldCheck}>Enforce Policy</NexButton>
              </div>
          </div>
      </NexModal>

      <NexModal isOpen={showStakeholderModal} onClose={() => setShowStakeholderModal(false)} title="Add Stakeholder">
          <div className="space-y-4">
              <NexFormGroup label="Principal">
                  <select className="prop-input" value={newStakeholderId} onChange={e => setNewStakeholderId(e.target.value)}>
                      <option value="">Select User...</option>
                      {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                  </select>
              </NexFormGroup>
              <NexFormGroup label="Case Role">
                  <select className="prop-input" value={newStakeholderRole} onChange={e => setNewStakeholderRole(e.target.value)}>
                      <option>Consultant</option><option>Approver</option><option>Auditor</option><option>Observer</option>
                  </select>
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleAddStakeholder} icon={Users}>Add to Case</NexButton>
              </div>
          </div>
      </NexModal>

      {showLaunchModal && (
        <div className="absolute inset-0 z-50 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-md rounded-sm border border-slate-300 p-6 shadow-xl animate-slide-up space-y-4">
              <div className="flex justify-between items-center">
                 <h3 className="text-lg font-bold text-slate-900">Select Blueprint</h3>
                 <button onClick={() => setShowLaunchModal(false)} className="p-1 text-slate-400 hover:text-slate-600"><X size={18}/></button>
              </div>
              <div className="space-y-2 max-h-80 overflow-y-auto border-t border-b border-slate-100 py-2">
                 {processes.map(proc => (
                   <button 
                     key={proc.id} 
                     onClick={() => handleLaunchWorkflow(proc.id)}
                     className="w-full p-3 border border-slate-200 rounded-sm flex items-center justify-between hover:border-blue-400 hover:bg-blue-50 transition-all text-left group"
                   >
                     <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-sm bg-slate-100 flex items-center justify-center text-slate-500 group-hover:bg-blue-600 group-hover:text-white transition-all"><Layers size={16}/></div>
