export const TaskInbox: React.FC = () => {
  const { tasks, completeTask, claimTask, releaseTask, addTaskComment, reassignTask, updateTaskMetadata, bulkCompleteTasks, currentUser, delegations, users, navigateTo, openInstanceViewer } = useBPM();
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [commentText, setCommentText] = useState('');

  // View State
  const [sortBy, setSortBy] = useState<'dueDate' | 'priority'>('dueDate');
  const [filterProcess, setFilterProcess] = useState('All');
  const [multiSelectMode, setMultiSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Modal States
  const [showReassign, setShowReassign] = useState(false);
  const [reassignTarget, setReassignTarget] = useState('');
  const [showMetadata, setShowMetadata] = useState(false);

  // Metadata Form State
  const [metaPriority, setMetaPriority] = useState<TaskPriority>(TaskPriority.MEDIUM);
  const [metaDueDate, setMetaDueDate] = useState('');

  // Derived Lists
  const delegateRules = delegations.filter(d => d.toUserId === currentUser?.id && d.isActive);

  const allRelevantTasks = tasks.filter(t => {
      const isMyTask = t.assignee === currentUser?.id;
      const isDelegated = delegateRules.some(d => d.fromUserId === t.assignee);
      const isUnassigned = t.status === TaskStatus.PENDING && t.assignee === 'Unassigned';

      // Filter Logic
      const matchesProcess = filterProcess === 'All' || t.processName === filterProcess;

      return (isMyTask || isDelegated || isUnassigned) && matchesProcess;
  });

  const sortedTasks = useMemo(() => {
      return [...allRelevantTasks].sort((a, b) => {
          if (sortBy === 'priority') {
              const pMap = { 'Critical': 4, 'High': 3, 'Medium': 2, 'Low': 1 };
              return pMap[b.priority] - pMap[a.priority];
          }
          return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
      });
  }, [allRelevantTasks, sortBy]);

  const myTasks = sortedTasks.filter(t => t.assignee === currentUser?.id);
  const delegatedTasks = sortedTasks.filter(t => delegateRules.some(d => d.fromUserId === t.assignee));
  const unassignedTasks = sortedTasks.filter(t => t.status === TaskStatus.PENDING && t.assignee === 'Unassigned');

  // Unique Process Names for Filter
  const processNames = Array.from(new Set(tasks.map(t => t.processName)));

  const handleAction = async (id: string, action: 'approve' | 'reject') => {
    await completeTask(id, action, action === 'approve' ? 'Approved' : 'Rejected');
    setSelectedTask(null);
  };

  const handleBulkAction = async (action: 'approve' | 'reject') => {
      await bulkCompleteTasks(Array.from(selectedIds), action);
      setSelectedIds(new Set());
      setMultiSelectMode(false);
  };

  const toggleSelection = (id: string) => {
      const newSet = new Set(selectedIds);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setSelectedIds(newSet);
  };

  const openReassign = () => { setReassignTarget(''); setShowReassign(true); };
  const handleReassign = async () => {
      if (selectedTask && reassignTarget) {
          await reassignTask(selectedTask.id, reassignTarget);
          setShowReassign(false);
          setSelectedTask(null);
      }
  };

  const openMetadata = () => {
      if (selectedTask) {
          setMetaPriority(selectedTask.priority);
          setMetaDueDate(selectedTask.dueDate.split('T')[0]);
          setShowMetadata(true);
      }
  };

  const handleUpdateMetadata = async () => {
      if (selectedTask) {
          await updateTaskMetadata(selectedTask.id, { priority: metaPriority, dueDate: new Date(metaDueDate).toISOString() });
          setShowMetadata(false);
      }
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-white border border-slate-300 rounded-sm shadow-sm overflow-hidden">

      {/* --- Modals --- */}
      <NexModal isOpen={showReassign} onClose={() => setShowReassign(false)} title="Transfer Ownership">
          <div className="space-y-4">
              <NexFormGroup label="New Owner">
                  <select className="prop-input" value={reassignTarget} onChange={e => setReassignTarget(e.target.value)}>
                      <option value="">Select Principal...</option>
                      {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                  </select>
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleReassign} icon={UserPlus}>Confirm Transfer</NexButton>
              </div>
          </div>
      </NexModal>

      <NexModal isOpen={showMetadata} onClose={() => setShowMetadata(false)} title="Task Parameters">
          <div className="space-y-4">
              <NexFormGroup label="Priority Level">
                  <select className="prop-input" value={metaPriority} onChange={e => setMetaPriority(e.target.value as TaskPriority)}>
                      {Object.values(TaskPriority).map(p => <option key={p} value={p}>{p}</option>)}
                  </select>
              </NexFormGroup>
              <NexFormGroup label="Due Date">
                  <input type="date" className="prop-input" value={metaDueDate} onChange={e => setMetaDueDate(e.target.value)} />
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleUpdateMetadata} icon={Settings}>Update Task</NexButton>
              </div>
          </div>
      </NexModal>

      {/* Master List */}
      <div className={`w-full lg:w-80 flex flex-col border-r border-slate-200 bg-white ${selectedTask ? 'hidden lg:flex' : 'flex'}`}>
        <div className="p-3 border-b border-slate-200 bg-slate-50 space-y-2">
           <div className="relative">
             <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"/>
             <input className="w-full pl-8 pr-3 py-1.5 text-xs border border-slate-300 rounded-sm focus:ring-1 focus:ring-blue-500 outline-none" placeholder="Filter tasks..." />
           </div>
           <div className="flex gap-1">
               <select className="flex-1 py-1 px-2 text-[10px] bg-slate-100 border border-slate-200 rounded-sm outline-none" value={sortBy} onChange={e => setSortBy(e.target.value as any)}>
                   <option value="dueDate">By Due Date</option>
                   <option value="priority">By Priority</option>
               </select>
               <select className="flex-1 py-1 px-2 text-[10px] bg-slate-100 border border-slate-200 rounded-sm outline-none" value={filterProcess} onChange={e => setFilterProcess(e.target.value)}>
                   <option value="All">All Flows</option>
                   {processNames.map(p => <option key={p} value={p}>{p}</option>)}
               </select>
           </div>
           <button 
             onClick={() => setMultiSelectMode(!multiSelectMode)} 
             className={`w-full py-1 text-[10px] font-bold uppercase rounded-sm border transition-all ${multiSelectMode ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
           >
             {multiSelectMode ? 'Cancel Selection' : 'Bulk Actions'}
           </button>
        </div>

        {/* Bulk Action Bar */}
        {multiSelectMode && selectedIds.size > 0 && (
            <div className="bg-blue-50 border-b border-blue-100 p-2 flex gap-2 justify-center animate-slide-up">
                <button onClick={() => handleBulkAction('approve')} className="flex-1 py-1 bg-emerald-600 text-white rounded-sm text-[10px] font-bold hover:bg-emerald-700">Approve ({selectedIds.size})</button>
                <button onClick={() => handleBulkAction('reject')} className="flex-1 py-1 bg-rose-600 text-white rounded-sm text-[10px] font-bold hover:bg-rose-700">Reject ({selectedIds.size})</button>
            </div>
        )}

        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-slate-500 uppercase border-y border-slate-200">My Worklist ({myTasks.length})</div>
          {myTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} isMultiSelectMode={multiSelectMode} isChecked={selectedIds.has(t.id)} onCheck={toggleSelection} onClick={setSelectedTask} />)}

          {delegatedTasks.length > 0 && (
            <>
              <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-blue-600 uppercase border-y border-slate-200 flex items-center gap-2"><ShieldAlert size={10}/> Delegated</div>
              {delegatedTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} isMultiSelectMode={multiSelectMode} isChecked={selectedIds.has(t.id)} onCheck={toggleSelection} onClick={setSelectedTask} />)}
            </>
          )}

          <div className="px-4 py-2 bg-slate-100 text-[10px] font-bold text-slate-500 uppercase border-y border-slate-200">Unassigned ({unassignedTasks.length})</div>
          {unassignedTasks.map(t => <ListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} isMultiSelectMode={multiSelectMode} isChecked={selectedIds.has(t.id)} onCheck={toggleSelection} onClick={setSelectedTask} />)}
        </div>
      </div>

      {/* Detail View */}
      <div className={`flex-1 flex flex-col bg-slate-50 ${selectedTask ? 'flex' : 'hidden lg:flex'}`}>
        {selectedTask ? (
          <>
            <div className="h-14 border-b border-slate-200 bg-white flex items-center justify-between px-6 shadow-sm z-10">
              <div className="flex items-center gap-3">
                <button onClick={() => setSelectedTask(null)} className="lg:hidden p-1 border rounded hover:bg-slate-100"><ChevronLeft size={16}/></button>
                <div className="flex flex-col">
                  <span className="text-[10px] font-mono text-slate-400">{selectedTask.id}</span>
                  <h2 className="text-sm font-bold text-slate-800">{selectedTask.title}</h2>
                </div>
              </div>
              <div className="flex gap-2">
                {selectedTask.assignee === 'Unassigned' ? (
                    <NexButton variant="primary" onClick={() => claimTask(selectedTask.id)} icon={CheckCircle}>Claim</NexButton>
                ) : (
                    <>
                        <NexButton variant="secondary" onClick={() => releaseTask(selectedTask.id)} icon={XCircle}>Release</NexButton>
                        <NexButton variant="secondary" onClick={openReassign} icon={UserPlus}>Reassign</NexButton>
                    </>
                )}
                <NexButton variant="secondary" onClick={openMetadata} icon={Settings}>Metadata</NexButton>
                <div className="h-6 w-px bg-slate-300 mx-2"></div>
                <NexButton variant="secondary" onClick={() => openInstanceViewer(selectedTask.processInstanceId)} icon={Layers}>Diagram</NexButton>
                {selectedTask.caseId && <NexButton variant="secondary" onClick={() => navigateTo('case-viewer', selectedTask.caseId)} icon={Briefcase}>Case</NexButton>}
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
               <div className="bg-white border border-slate-300 rounded-sm p-6 mb-6 shadow-sm">
                  <div className="flex justify-between items-start mb-4 border-b border-slate-100 pb-2">
                      <h3 className="text-xs font-bold text-slate-700 uppercase">Task Context</h3>
                      {selectedTask.isAdHoc && <NexBadge variant="amber">Ad-Hoc</NexBadge>}
                  </div>
                  <p className="text-sm text-slate-700 leading-relaxed mb-6">{selectedTask.description || "No specific instructions provided for this task."}</p>

                  <div className="grid grid-cols-2 gap-4 text-xs">
                    <div><span className="text-slate-500 block mb-1">Process</span> <span className="font-medium">{selectedTask.processName}</span></div>
                    <div><span className="text-slate-500 block mb-1">Priority</span> <NexBadge variant={selectedTask.priority === 'Critical' ? 'rose' : 'blue'}>{selectedTask.priority}</NexBadge></div>
                    <div><span className="text-slate-500 block mb-1">Due Date</span> <span className="font-medium">{new Date(selectedTask.dueDate).toLocaleDateString()}</span></div>
                    <div><span className="text-slate-500 block mb-1">Assignee</span> <span className="font-medium">{selectedTask.assignee}</span></div>
                  </div>
               </div>

               <div className="bg-white border border-slate-300 rounded-sm p-6 shadow-sm">
                  <h3 className="text-xs font-bold text-slate-700 uppercase border-b border-slate-100 pb-2 mb-4">Activity Log</h3>
                  <NexHistoryFeed history={selectedTask.comments} />
                  <div className="mt-4 pt-4 border-t border-slate-100 flex gap-2">
                     <input className="prop-input" placeholder="Add comment..." value={commentText} onChange={e => setCommentText(e.target.value)} />
                     <NexButton onClick={() => { if(selectedTask && commentText) { addTaskComment(selectedTask.id, commentText); setCommentText(''); }}} icon={Send}>Add</NexButton>
                  </div>
               </div>
            </div>

            <div className="p-4 border-t border-slate-300 bg-white flex justify-end gap-3">
              <NexButton variant="danger" onClick={() => handleAction(selectedTask.id, 'reject')} disabled={selectedTask.assignee === 'Unassigned'}>Reject</NexButton>
              <NexButton variant="primary" onClick={() => handleAction(selectedTask.id, 'approve')} disabled={selectedTask.assignee === 'Unassigned'}>Approve & Complete</NexButton>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <CheckSquare size={48} className="mb-4 opacity-20"/>
            <p className="text-sm font-medium">Select a task item to view details</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  Users, Shield, Landmark, UserPlus, Search, 
  MoreVertical, Key, User as UserIcon, PlusCircle, Trash2, Globe, Fingerprint, Lock,
  Clock, X, ChevronRight, ShieldAlert, CheckSquare, Plus, Edit, Slash
} from 'lucide-react';
import { Permission, User } from '../types';
import { TabBtn } from './identity/TabBtn';
import { IntegrationCard } from './identity/IntegrationCard';
import { PolicyItem } from './identity/PolicyItem';
import { NexButton, NexBadge, NexCard, NexModal, NexFormGroup } from './shared/NexUI';

export const IdentityView: React.FC = () => {
  const { users, roles, groups, delegations, hasPermission, currentUser, revokeDelegation, createDelegation, createUser, updateUser, deleteUser, createRole, updateRole, deleteRole, createGroup, updateGroup, deleteGroup } = useBPM();
  const [activeTab, setActiveTab] = useState<'profile' | 'users' | 'roles' | 'groups' | 'sso'>('profile');
  const [searchQuery, setSearchQuery] = useState('');

  // Modal States
  const [showDelModal, setShowDelModal] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);
  const [showRoleModal, setShowRoleModal] = useState(false);
  const [showGroupModal, setShowGroupModal] = useState(false);

  // Edit Mode IDs (null = create)
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [editingRoleId, setEditingRoleId] = useState<string | null>(null);
  const [editingGroupId, setEditingGroupId] = useState<string | null>(null);

  // Form States
  const [delTargetId, setDelTargetId] = useState('');
  const [delScope, setDelScope] = useState<'All' | 'Critical Only'>('All');

  const [userForm, setUserForm] = useState({ name: '', email: '', roleId: '', groupId: '', location: '', skills: '' });
  const [roleForm, setRoleForm] = useState({ name: '', permissions: [] as Permission[] });
  const [groupForm, setGroupForm] = useState({ name: '', parentGroupId: '', description: '' });

  const canManageUsers = hasPermission(Permission.USER_MANAGE);

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    u.email.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const myDelegations = delegations.filter(d => d.fromUserId === currentUser?.id);

  // --- Handlers ---

  const openCreateUser = () => {
      setEditingUserId(null);
      setUserForm({ name: '', email: '', roleId: '', groupId: '', location: '', skills: '' });
      setShowUserModal(true);
  };

  const openEditUser = (u: User) => {
      setEditingUserId(u.id);
      setUserForm({ 
          name: u.name, 
          email: u.email, 
          roleId: u.roleIds[0] || '', 
          groupId: u.groupIds[0] || '', 
          location: u.location, 
          skills: u.skills.join(', ') 
      });
      setShowUserModal(true);
  };

  const handleSubmitUser = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
        name: userForm.name,
        email: userForm.email,
        roleIds: [userForm.roleId],
        groupIds: [userForm.groupId],
        location: userForm.location,
        skills: userForm.skills.split(',').map(s => s.trim()),
        status: 'Active' as const,
        domainId: currentUser?.domainId || 'GLOBAL'
    };

    if (editingUserId) {
        await updateUser(editingUserId, payload);
    } else {
        await createUser(payload);
    }
    setShowUserModal(false);
  };

  const handleDeactivateUser = async (id: string) => {
      await updateUser(id, { status: 'Terminated' });
  };

  const openCreateRole = () => {
      setEditingRoleId(null);
      setRoleForm({ name: '', permissions: [] });
      setShowRoleModal(true);
  };

  const openEditRole = (r: any) => {
      setEditingRoleId(r.id);
      setRoleForm({ name: r.name, permissions: r.permissions });
      setShowRoleModal(true);
  };

  const handleSubmitRole = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingRoleId) {
        await updateRole(editingRoleId, roleForm);
    } else {
        await createRole(roleForm);
    }
    setShowRoleModal(false);
  };

  const openCreateGroup = () => {
      setEditingGroupId(null);
      setGroupForm({ name: '', parentGroupId: '', description: '' });
      setShowGroupModal(true);
  };

  const openEditGroup = (g: any) => {
      setEditingGroupId(g.id);
      setGroupForm({ name: g.name, parentGroupId: g.parentGroupId || '', description: g.description });
      setShowGroupModal(true);
  };

  const handleSubmitGroup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingGroupId) {
        await updateGroup(editingGroupId, groupForm);
    } else {
        await createGroup(groupForm);
    }
    setShowGroupModal(false);
  };

  const togglePermission = (p: Permission) => {
    if (roleForm.permissions.includes(p)) {
        setRoleForm({ ...roleForm, permissions: roleForm.permissions.filter(x => x !== p) });
    } else {
        setRoleForm({ ...roleForm, permissions: [...roleForm.permissions, p] });
    }
  };

  const handleCreateDelegation = async () => {
    if (!delTargetId) return;
    await createDelegation(delTargetId, delScope);
    setShowDelModal(false);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20 relative">
      <header className="flex flex-col gap-4 border-b border-slate-300 pb-4">
        <div>
          <h2 className="text-xl font-bold text-slate-900 tracking-tight">Identity & Access</h2>
          <p className="text-xs text-slate-500 font-medium">Principal management and directory protocols.</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-sm border border-slate-200 overflow-x-auto">
           <TabBtn active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={UserIcon} label="My Session" />
           <TabBtn active={activeTab === 'users'} onClick={() => setActiveTab('users')} icon={Users} label="Principals" />
           <TabBtn active={activeTab === 'roles'} onClick={() => setActiveTab('roles')} icon={Shield} label="Roles" />
           <TabBtn active={activeTab === 'groups'} onClick={() => setActiveTab('groups')} icon={Landmark} label="Groups" />
           <TabBtn active={activeTab === 'sso'} onClick={() => setActiveTab('sso')} icon={Fingerprint} label="Directory" />
        </div>
      </header>

      {/* --- Modals --- */}
      <NexModal isOpen={showDelModal} onClose={() => setShowDelModal(false)} title="Proxy Assignment">
         <div className="space-y-4">
            <NexFormGroup label="Assignee">
                <select className="prop-input" value={delTargetId} onChange={e => setDelTargetId(e.target.value)}>
                    <option value="">Select User...</option>
                    {users.filter(u => u.id !== currentUser?.id).map(u => (
                    <option key={u.id} value={u.id}>{u.name} ({u.email})</option>
                    ))}
                </select>
            </NexFormGroup>
            <NexFormGroup label="Scope">
                <div className="flex gap-2">
                    <button onClick={() => setDelScope('All')} className={`flex-1 py-2 rounded-sm text-xs font-bold border transition-all ${delScope === 'All' ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-600 border-slate-300'}`}>Full</button>
                    <button onClick={() => setDelScope('Critical Only')} className={`flex-1 py-2 rounded-sm text-xs font-bold border transition-all ${delScope === 'Critical Only' ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-slate-600 border-slate-300'}`}>Critical</button>
                </div>
            </NexFormGroup>
            <NexButton variant="primary" onClick={handleCreateDelegation} className="w-full">Activate Proxy</NexButton>
         </div>
      </NexModal>

      <NexModal isOpen={showUserModal} onClose={() => setShowUserModal(false)} title={editingUserId ? "Edit Profile" : "Provision New Identity"}>
         <form onSubmit={handleSubmitUser} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <NexFormGroup label="Full Name">
                    <input required className="prop-input" value={userForm.name} onChange={e => setUserForm({...userForm, name: e.target.value})} placeholder="e.g. Sarah Connor" />
                </NexFormGroup>
                <NexFormGroup label="Email Address">
                    <input required type="email" className="prop-input" value={userForm.email} onChange={e => setUserForm({...userForm, email: e.target.value})} placeholder="corp@nexflow.com" />
                </NexFormGroup>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <NexFormGroup label="Primary Role">
                    <select required className="prop-input" value={userForm.roleId} onChange={e => setUserForm({...userForm, roleId: e.target.value})}>
                        <option value="">Select Role...</option>
                        {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </select>
                </NexFormGroup>
                <NexFormGroup label="Department Group">
                    <select required className="prop-input" value={userForm.groupId} onChange={e => setUserForm({...userForm, groupId: e.target.value})}>
                        <option value="">Select Group...</option>
                        {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                    </select>
                </NexFormGroup>
            </div>
            <NexFormGroup label="Office Location">
                <input className="prop-input" value={userForm.location} onChange={e => setUserForm({...userForm, location: e.target.value})} placeholder="e.g. London HQ" />
            </NexFormGroup>
            <NexFormGroup label="Skills (CSV)">
                <input className="prop-input" value={userForm.skills} onChange={e => setUserForm({...userForm, skills: e.target.value})} placeholder="BPMN, Audit, Java..." />
            </NexFormGroup>
            <div className="flex justify-end pt-2">
                <NexButton type="submit" variant="primary" icon={Plus}>{editingUserId ? "Update User" : "Provision User"}</NexButton>
            </div>
         </form>
      </NexModal>

      <NexModal isOpen={showRoleModal} onClose={() => setShowRoleModal(false)} title={editingRoleId ? "Edit Role" : "Define RBAC Role"} size="lg">
         <form onSubmit={handleSubmitRole} className="space-y-4">
            <NexFormGroup label="Role Name">
                <input required className="prop-input" value={roleForm.name} onChange={e => setRoleForm({...roleForm, name: e.target.value})} placeholder="e.g. Compliance Auditor" />
            </NexFormGroup>
            <NexFormGroup label="Permission Scopes">
                <div className="grid grid-cols-2 gap-2 max-h-60 overflow-y-auto p-2 border border-slate-200 rounded-sm bg-slate-50">
                    {Object.values(Permission).map(p => (
                        <label key={p} className="flex items-center gap-2 p-2 hover:bg-white border border-transparent hover:border-slate-200 rounded-sm cursor-pointer transition-all">
                            <input type="checkbox" checked={roleForm.permissions.includes(p)} onChange={() => togglePermission(p)} className="rounded-sm border-slate-300 text-blue-600 focus:ring-blue-500" />
                            <span className="text-xs font-medium text-slate-700">{p}</span>
                        </label>
                    ))}
                </div>
            </NexFormGroup>
            <div className="flex justify-end pt-2">
                <NexButton type="submit" variant="primary" icon={Shield}>{editingRoleId ? "Update Role" : "Create Role"}</NexButton>
            </div>
         </form>
      </NexModal>

      <NexModal isOpen={showGroupModal} onClose={() => setShowGroupModal(false)} title={editingGroupId ? "Edit Organization Unit" : "Create Organization Unit"}>
         <form onSubmit={handleSubmitGroup} className="space-y-4">
            <NexFormGroup label="Unit Name">
                <input required className="prop-input" value={groupForm.name} onChange={e => setGroupForm({...groupForm, name: e.target.value})} placeholder="e.g. APAC Sales" />
            </NexFormGroup>
            <NexFormGroup label="Parent Unit">
                <select className="prop-input" value={groupForm.parentGroupId} onChange={e => setGroupForm({...groupForm, parentGroupId: e.target.value})}>
                    <option value="">Root Level</option>
                    {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
            </NexFormGroup>
            <NexFormGroup label="Description">
                <textarea className="prop-input h-20 resize-none" value={groupForm.description} onChange={e => setGroupForm({...groupForm, description: e.target.value})} placeholder="Operational scope..." />
            </NexFormGroup>
            <div className="flex justify-end pt-2">
                <NexButton type="submit" variant="primary" icon={Landmark}>{editingGroupId ? "Update Group" : "Establish Group"}</NexButton>
            </div>
         </form>
      </NexModal>

      {/* --- Main Content --- */}

      {activeTab === 'profile' && currentUser && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
           <NexCard className="lg:col-span-1 p-0 flex flex-col">
              <div className="p-6 text-center border-b border-slate-200 bg-slate-50">
                 <div className="w-16 h-16 bg-white border border-slate-300 rounded-sm flex items-center justify-center text-2xl font-bold text-slate-800 mx-auto mb-3 shadow-sm">
                    {currentUser?.name?.charAt(0) || '?'}
                 </div>
                 <h3 className="text-base font-bold text-slate-900">{currentUser?.name}</h3>
                 <p className="text-xs text-slate-500 font-mono mb-3">{currentUser?.email}</p>
                 <div className="flex flex-wrap justify-center gap-1">
                    {currentUser?.roleIds?.map(rid => (
                      <span key={rid} className="px-2 py-0.5 bg-slate-200 text-slate-700 rounded-sm text-[10px] font-bold uppercase">
                        {roles.find(r => r.id === rid)?.name || 'Role'}
                      </span>
                    ))}
                 </div>
              </div>
              <div className="p-4 space-y-2">
                 <div className="flex justify-between text-xs border-b border-slate-100 pb-2">
                    <span className="text-slate-500 font-medium">Location</span>
                    <span className="font-bold text-slate-800">{currentUser?.location}</span>
                 </div>
                 <div className="flex justify-between text-xs">
                    <span className="text-slate-500 font-medium">Unit</span>
                    <span className="font-bold text-slate-800">{groups.find(g => currentUser?.groupIds?.includes(g.id))?.name || 'Global'}</span>
                 </div>
              </div>
           </NexCard>

           <NexCard className="lg:col-span-2 p-6">
              <div className="flex items-center justify-between mb-6">
                 <div>
                    <h3 className="text-sm font-bold text-slate-900 flex items-center gap-2">
                      <Key size={16} className="text-blue-600"/> Delegation & Proxy
                    </h3>
                    <p className="text-xs text-slate-500 mt-0.5">Manage temporary authority transfers.</p>
                 </div>
                 <NexButton variant="secondary" onClick={() => setShowDelModal(true)} icon={PlusCircle}>New Record</NexButton>
              </div>

              <div className="space-y-2">
                 {myDelegations.length === 0 ? (
                   <div className="p-8 border border-dashed border-slate-200 rounded-sm text-center bg-slate-50">
                     <p className="text-xs text-slate-400 font-bold uppercase">No Active Delegations</p>
                   </div>
                 ) : (
                   myDelegations.map(del => (
                     <div key={del.id} className="p-3 bg-slate-50 border border-slate-200 rounded-sm flex items-center justify-between">
                        <div className="flex items-center gap-3">
                           <div className="w-8 h-8 bg-white border border-slate-300 rounded-sm flex items-center justify-center font-bold text-xs text-slate-700">
                             {users.find(u => u.id === del.toUserId)?.name?.charAt(0)}
                           </div>
                           <div>
                              <p className="text-xs font-bold text-slate-800">To: {users.find(u => u.id === del.toUserId)?.name}</p>
                              <div className="flex items-center gap-2">
                                 <span className="text-[10px] text-slate-500">Until: {new Date(del.endDate).toLocaleDateString()}</span>
                                 <span className={`text-[9px] font-bold px-1 rounded-sm border ${del.scope === 'Critical Only' ? 'bg-rose-50 text-rose-600 border-rose-200' : 'bg-blue-50 text-blue-600 border-blue-200'}`}>{del.scope}</span>
                              </div>
                           </div>
                        </div>
                        <button onClick={() => revokeDelegation(del.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-sm"><Trash2 size={14}/></button>
                     </div>
                   ))
                 )}
              </div>
           </NexCard>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="space-y-4">
          <div className="flex gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14}/>
              <input 
                className="w-full pl-9 pr-4 py-2 bg-white border border-slate-300 rounded-sm text-xs font-medium focus:ring-1 focus:ring-blue-600 outline-none"
                placeholder="Search principals..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {canManageUsers && (
               <NexButton variant="primary" icon={UserPlus} onClick={openCreateUser}>Provision</NexButton>
            )}
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredUsers.map(user => (
              <NexCard key={user.id} className="p-4 flex flex-col gap-3 group relative">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-sm bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-sm border border-slate-200">
                        {user.name.charAt(0)}
                    </div>
                    <div>
                        <h4 className="font-bold text-slate-800 text-sm">{user.name}</h4>
                        <p className="text-[11px] text-slate-500 truncate max-w-[140px]">{user.email}</p>
                    </div>
                  </div>
                  <NexBadge variant={user.status === 'Active' ? 'emerald' : 'rose'}>{user.status}</NexBadge>
                </div>
                <div className="pt-3 border-t border-slate-100 flex items-center justify-between text-[10px]">
                   <span className="font-bold text-slate-400 uppercase flex items-center gap-1">
                      <Lock size={10}/> {roles.find(r => user.roleIds.includes(r.id))?.name || 'Authorized'}
                   </span>
                   {/* User Actions */}
                   <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                       <button onClick={() => openEditUser(user)} className="p-1 hover:bg-slate-100 rounded text-blue-600"><Edit size={14}/></button>
                       <button onClick={() => handleDeactivateUser(user.id)} className="p-1 hover:bg-slate-100 rounded text-amber-600" title="Deactivate"><Slash size={14}/></button>
                       <button onClick={() => deleteUser(user.id)} className="p-1 hover:bg-slate-100 rounded text-rose-600"><Trash2 size={14}/></button>
                   </div>
                </div>
              </NexCard>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'roles' && (
          <div className="space-y-4">
              <div className="flex justify-end">
                  <NexButton variant="secondary" icon={Shield} onClick={openCreateRole}>Define Role</NexButton>
              </div>
              <div className="grid gap-4">
                  {roles.map(role => (
                      <NexCard key={role.id} className="p-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4 group">
                          <div>
                              <h4 className="font-bold text-slate-900 text-sm mb-1">{role.name}</h4>
                              <p className="text-[10px] text-slate-500 font-mono">{role.id}</p>
                          </div>
                          <div className="flex items-center gap-4">
                              <div className="flex flex-wrap gap-1 justify-end">
                                  {role.permissions.slice(0, 5).map(p => (
                                      <span key={p} className="px-2 py-0.5 bg-slate-100 text-slate-600 border border-slate-200 rounded-sm text-[9px] font-medium">{p}</span>
                                  ))}
                                  {role.permissions.length > 5 && <span className="px-2 py-0.5 text-[9px] text-slate-400">+{role.permissions.length - 5} more</span>}
                              </div>
                              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={() => openEditRole(role)} className="p-1 hover:bg-slate-100 rounded text-blue-600"><Edit size={14}/></button>
                                  <button onClick={() => deleteRole(role.id)} className="p-1 hover:bg-slate-100 rounded text-rose-600"><Trash2 size={14}/></button>
                              </div>
                          </div>
                      </NexCard>
                  ))}
              </div>
          </div>
      )}

      {activeTab === 'groups' && (
          <div className="space-y-4">
              <div className="flex justify-end">
                  <NexButton variant="secondary" icon={Landmark} onClick={openCreateGroup}>Create Group</NexButton>
              </div>
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                  {groups.map(group => (
                      <NexCard key={group.id} className="p-4 group relative">
                          <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={() => openEditGroup(group)} className="p-1 hover:bg-slate-100 rounded text-blue-600"><Edit size={14}/></button>
                              <button onClick={() => deleteGroup(group.id)} className="p-1 hover:bg-slate-100 rounded text-rose-600"><Trash2 size={14}/></button>
                          </div>
                          <div className="flex items-start justify-between mb-3">
                              <Landmark size={20} className="text-slate-400"/>
                              {group.parentGroupId && <span className="text-[9px] font-bold text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded-sm border border-blue-100">Sub-Unit</span>}
                          </div>
                          <h4 className="font-bold text-slate-900 text-sm mb-1">{group.name}</h4>
                          <p className="text-xs text-slate-500 leading-snug">{group.description}</p>
                      </NexCard>
                  ))}
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  ArrowLeft, Users, Send, Settings, Activity, 
  CheckSquare, ChevronRight, Briefcase, ShieldCheck, Play, X, Layers, Plus, Shield, Edit, Trash2, RotateCcw, Lock
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexCard, NexModal, NexFormGroup } from './shared/NexUI';

export const CaseViewer: React.FC<{ caseId: string }> = ({ caseId }) => {
  const { cases, tasks, processes, users, navigateTo, addCaseEvent, removeCaseEvent, addCasePolicy, removeCasePolicy, addCaseStakeholder, removeCaseStakeholder, updateCase, startProcess, currentUser, openInstanceViewer } = useBPM();
  const [activeTab, setActiveTab] = useState<'timeline' | 'tasks' | 'data' | 'content'>('timeline');
  const [note, setNote] = useState('');

  // Modals
  const [showLaunchModal, setShowLaunchModal] = useState(false);
  const [showPolicyModal, setShowPolicyModal] = useState(false);
  const [showStakeholderModal, setShowStakeholderModal] = useState(false);
  const [showEditCase, setShowEditCase] = useState(false);

  // Forms
  const [newPolicy, setNewPolicy] = useState('');
  const [newStakeholderId, setNewStakeholderId] = useState('');
  const [newStakeholderRole, setNewStakeholderRole] = useState('Consultant');
  const [editTitle, setEditTitle] = useState('');
  const [editDesc, setEditDesc] = useState('');

  const currentCase = cases.find(c => c.id === caseId);
  const relatedTasks = useMemo(() => tasks.filter(t => t.caseId === caseId), [tasks, caseId]);

  if (!currentCase) return <div className="p-20 text-center text-slate-400">Case file not found.</div>;

  const handlePostNote = async (e: React.SyntheticEvent) => {
    e.preventDefault();
    if (!note.trim()) return;
    await addCaseEvent(caseId, note);
    setNote('');
  };

  const handleLaunchWorkflow = async (procId: string) => {
    await startProcess(procId, { summary: `Auto-launched from case: ${currentCase.title}` }, caseId);
    setShowLaunchModal(false);
    setActiveTab('tasks');
  };

  const handleAddPolicy = async () => {
      if (newPolicy) {
          await addCasePolicy(caseId, newPolicy);
          setShowPolicyModal(false);
          setNewPolicy('');
      }
  };

  const handleAddStakeholder = async () => {
      if (newStakeholderId) {
          await addCaseStakeholder(caseId, newStakeholderId, newStakeholderRole);
          setShowStakeholderModal(false);
          setNewStakeholderId('');
      }
  };

  const openEdit = () => {
      setEditTitle(currentCase.title);
      setEditDesc(currentCase.description);
      setShowEditCase(true);
  };

  const handleUpdateCase = async () => {
      await updateCase(caseId, { title: editTitle, description: editDesc });
      setShowEditCase(false);
  };

  const handleCloseCase = async () => {
      await updateCase(caseId, { status: 'Closed', resolvedAt: new Date().toISOString() });
      await addCaseEvent(caseId, 'Case officially closed.');
  };

  const handleReopenCase = async () => {
      await updateCase(caseId, { status: 'Open' });
      await addCaseEvent(caseId, 'Case reopened for further action.');
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] animate-fade-in bg-white rounded-sm border border-slate-300 shadow-sm overflow-hidden relative">
      <header className="h-14 px-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
        <div className="flex items-center gap-3">
          <button onClick={() => navigateTo('cases')} className="p-1 hover:bg-white border border-transparent hover:border-slate-200 rounded-sm transition-all"><ArrowLeft size={16}/></button>
          <div className="h-6 w-px bg-slate-300 mx-1"></div>
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-sm font-bold text-slate-800">{currentCase.title}</h2>
              <NexBadge variant={currentCase.status === 'Closed' ? 'slate' : 'blue'}>{currentCase.status}</NexBadge>
            </div>
            <p className="text-[10px] text-slate-400 font-mono">{currentCase.id}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <button onClick={openEdit} className="p-1.5 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-sm"><Edit size={16}/></button>
           {currentCase.status !== 'Closed' ? (
                <NexButton variant="danger" icon={Lock} onClick={handleCloseCase}>Close Case</NexButton>
           ) : (
                <NexButton variant="primary" icon={RotateCcw} onClick={handleReopenCase}>Reopen</NexButton>
           )}
           <div className="h-6 w-px bg-slate-300 mx-1"></div>
           <NexButton variant="secondary" icon={Play} onClick={() => setShowLaunchModal(true)} disabled={currentCase.status === 'Closed'}>Action</NexButton>
        </div>
      </header>

      {/* --- Modals --- */}
      <NexModal isOpen={showEditCase} onClose={() => setShowEditCase(false)} title="Edit Case Details">
          <div className="space-y-4">
              <NexFormGroup label="Case Title">
                  <input className="prop-input" value={editTitle} onChange={e => setEditTitle(e.target.value)} />
              </NexFormGroup>
              <NexFormGroup label="Description">
                  <textarea className="prop-input h-32 resize-none" value={editDesc} onChange={e => setEditDesc(e.target.value)} />
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleUpdateCase} icon={Edit}>Save Changes</NexButton>
              </div>
          </div>
      </NexModal>

      <NexModal isOpen={showPolicyModal} onClose={() => setShowPolicyModal(false)} title="Attach Policy">
          <div className="space-y-4">
              <NexFormGroup label="Policy Statement">
                  <textarea className="prop-input h-32 resize-none" value={newPolicy} onChange={e => setNewPolicy(e.target.value)} placeholder="e.g. All refunds > $500 must have VP approval..." />
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleAddPolicy} icon={ShieldCheck}>Enforce Policy</NexButton>
              </div>
          </div>
      </NexModal>

      <NexModal isOpen={showStakeholderModal} onClose={() => setShowStakeholderModal(false)} title="Add Stakeholder">
          <div className="space-y-4">
              <NexFormGroup label="Principal">
                  <select className="prop-input" value={newStakeholderId} onChange={e => setNewStakeholderId(e.target.value)}>
                      <option value="">Select User...</option>
                      {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                  </select>
              </NexFormGroup>
              <NexFormGroup label="Case Role">
                  <select className="prop-input" value={newStakeholderRole} onChange={e => setNewStakeholderRole(e.target.value)}>
                      <option>Consultant</option><option>Approver</option><option>Auditor</option><option>Observer</option>
                  </select>
              </NexFormGroup>
              <div className="flex justify-end">
                  <NexButton variant="primary" onClick={handleAddStakeholder} icon={Users}>Add to Case</NexButton>
              </div>
          </div>
      </NexModal>

      {showLaunchModal && (
        <div className="absolute inset-0 z-50 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-md rounded-sm border border-slate-300 p-6 shadow-xl animate-slide-up space-y-4">
              <div className="flex justify-between items-center">
                 <h3 className="text-lg font-bold text-slate-900">Select Blueprint</h3>
                 <button onClick={() => setShowLaunchModal(false)} className="p-1 text-slate-400 hover:text-slate-600"><X size={18}/></button>
              </div>
              <div className="space-y-2 max-h-80 overflow-y-auto border-t border-b border-slate-100 py-2">
                 {processes.map(proc => (
                   <button 
                     key={proc.id} 
                     onClick={() => handleLaunchWorkflow(proc.id)}
                     className="w-full p-3 border border-slate-200 rounded-sm flex items-center justify-between hover:border-blue-400 hover:bg-blue-50 transition-all text-left group"
                   >
                     <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-sm bg-slate-100 flex items-center justify-center text-slate-500 group-hover:bg-blue-600 group-hover:text-white transition-all"><Layers size={16}/></div>
                        <span className="font-bold text-xs text-slate-800">{proc.name}</span>
                     </div>
                     <ChevronRight size={14} className="text-slate-300 group-hover:text-blue-600" />
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      <div className="flex-1 flex overflow-hidden">
        <aside className="w-64 border-r border-slate-200 flex flex-col hidden xl:flex p-4 bg-slate-50 space-y-6 overflow-y-auto">
           <div>
              <div className="flex justify-between items-center mb-2">
                  <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Stakeholders</h4>
                  <button onClick={() => setShowStakeholderModal(true)} className="text-blue-600 hover:text-blue-700"><Plus size={12}/></button>
              </div>
              <div className="space-y-2">
                 {currentCase.stakeholders.map((sh, i) => {
                     const u = users.find(user => user.id === sh.userId);
                     return (
                         <div key={i} className="flex items-center justify-between gap-2 p-2 bg-white border border-slate-200 rounded-sm group">
                             <div className="flex items-center gap-2 overflow-hidden">
                                <div className="w-6 h-6 rounded-sm bg-slate-100 flex items-center justify-center font-bold text-[10px] text-slate-600">{u?.name[0] || 'U'}</div>
                                <div className="overflow-hidden">
                                    <p className="text-xs font-bold truncate">{u?.name || 'Unknown'}</p>
                                    <p className="text-[9px] text-slate-500">{sh.role}</p>
                                </div>
                             </div>
                             <button onClick={() => removeCaseStakeholder(caseId, sh.userId)} className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-rose-600 transition-opacity"><Trash2 size={12}/></button>
                         </div>
                     );
                 })}
              </div>
           </div>

           <div className="space-y-3 pt-3 border-t border-slate-200">
              <div className="flex justify-between items-center mb-1">
                  <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Active Policies</h4>
                  <button onClick={() => setShowPolicyModal(true)} className="text-blue-600 hover:text-blue-700"><Plus size={12}/></button>
              </div>
              <div className="space-y-2">
                  {currentCase.policies.map((pol, i) => (
                      <div key={i} className="p-2 bg-amber-50 border border-amber-200 rounded-sm text-[10px] text-amber-900 font-medium flex justify-between items-start gap-2 group">
                          <div className="flex gap-2">
                            <Shield size={12} className="shrink-0 mt-0.5"/>
                            {pol.description}
                          </div>
                          <button onClick={() => removeCasePolicy(caseId, pol.id)} className="opacity-0 group-hover:opacity-100 text-amber-400 hover:text-amber-800 transition-opacity"><X size={12}/></button>
                      </div>
                  ))}
                  {currentCase.policies.length === 0 && <div className="text-[10px] text-slate-400 italic">No specific policies attached.</div>}
              </div>
           </div>
        </aside>

        <main className="flex-1 flex flex-col bg-white">
           <div className="flex border-b border-slate-200 bg-white">
              {['timeline', 'tasks', 'data', 'content'].map(tab => (
                <button 
                  key={tab} 
                  onClick={() => setActiveTab(tab as any)} 
                  className={`px-6 py-3 text-xs font-bold uppercase tracking-wider transition-all border-b-2 ${activeTab === tab ? 'text-blue-600 border-blue-600' : 'text-slate-500 border-transparent hover:text-slate-800'}`}
                >
                  {tab}
                </button>
              ))}
           </div>

           <div className="flex-1 overflow-y-auto p-6 bg-slate-50">
              {activeTab === 'timeline' && (
                <div className="max-w-2xl mx-auto space-y-6">
                   <div className="bg-white p-4 rounded-sm border border-slate-300 shadow-sm">
                      <div className="flex gap-3 mb-3">
                         <div className="w-8 h-8 rounded-sm bg-blue-100 border border-blue-200 flex items-center justify-center text-blue-700 font-bold shrink-0 text-xs">{currentUser?.name[0]}</div>
                         <textarea className="flex-1 bg-transparent outline-none text-xs min-h-[60px] resize-none" placeholder="Post a case note..." value={note} onChange={e => setNote(e.target.value)} />
                      </div>
                      <div className="flex justify-end">
                         <NexButton variant="primary" onClick={handlePostNote} icon={Send}>Post</NexButton>
                      </div>
                   </div>
                   <NexHistoryFeed history={currentCase.timeline} />
                </div>
              )}

              {activeTab === 'tasks' && (
                <div className="max-w-3xl mx-auto space-y-3">
                  {relatedTasks.map(task => {
                    return (
                      <div key={task.id} className="bg-white p-4 rounded-sm border border-slate-300 shadow-sm flex items-center justify-between group hover:border-blue-400 transition-all">
                        <div className="flex items-center gap-4">
                          <div className="w-8 h-8 rounded-sm flex items-center justify-center bg-slate-100 text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600 transition-all border border-slate-200">
                            <CheckSquare size={16} />
                          </div>
                          <div>
                            <h4 className="text-sm font-bold text-slate-900">{task.title}</h4>
                            <div className="flex items-center gap-2 mt-0.5">
                              <NexBadge variant={task.priority === 'Critical' ? 'rose' : 'blue'}>{task.priority}</NexBadge>
                              <span className="text-[10px] text-slate-400 font-bold uppercase">{task.status}</span>
                            </div>
                          </div>
                        </div>
                        <div className="flex gap-2">
                          <NexButton variant="secondary" onClick={() => openInstanceViewer(task.processInstanceId)} icon={Activity} />
                          <NexButton variant="primary" onClick={() => navigateTo('inbox', task.id)} icon={ChevronRight} />
                        </div>
                      </div>
                    );
                  })}
                  {relatedTasks.length === 0 && (
                    <div className="p-12 text-center text-slate-400 italic text-xs">No tasks associated with this case.</div>
                  )}
                </div>
              )}
           </div>
        </main>
      </div>
    </div>
  );
};

export enum TaskStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export enum Permission {
  PROCESS_VIEW = 'process:view',
  PROCESS_DEPLOY = 'process:deploy',
  PROCESS_START = 'process:start',
  TASK_COMPLETE = 'task:complete',
  TASK_OVERRIDE = 'task:override',
  ADMIN_ACCESS = 'admin:access',
  USER_MANAGE = 'user:manage',
  SYSTEM_CONFIG = 'system:config',
  CASE_MANAGE = 'case:manage',
  RULES_MANAGE = 'rules:manage',
  ANALYTICS_VIEW_ALL = 'analytics:view_all'
}

export interface UserRole {
  id: string;
  name: string;
  permissions: Permission[];
}

export interface UserGroup {
  id: string;
  name: string;
  parentGroupId?: string;
  description: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar?: string;
  roleIds: string[];
  groupIds: string[];
  skills: string[];
  location: string;
  status: 'Active' | 'On Leave' | 'Terminated';
  delegateToId?: string; 
  lastLogin?: string;
  domainId: string;
}

export interface Delegation {
  id: string;
  fromUserId: string;
  toUserId: string;
  startDate: string;
  endDate: string;
  isActive: boolean;
  scope: 'All' | 'Critical Only';
}

export interface Comment {
  id: string;
  userId: string;
  userName: string;
  text: string;
  timestamp: string;
}

export interface Attachment {
  id: string;
  name: string;
  type: 'internal' | 'external-link';
  size?: number;
  uploadDate: string;
  url?: string; // For external CMIS links
}

export interface Task {
  id:string;
  title: string;
  processName: string; // "Ad-Hoc" if case task
  processInstanceId: string; // or caseId
  assignee: string; 
  candidateRoles: string[]; 
  candidateGroups: string[];
  requiredSkills: string[];
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string; // or 'adhoc'
  data?: any;
  comments: Comment[];
  attachments: Attachment[];
  isAdHoc: boolean;
  caseId?: string;
}

export type ProcessStepType = 
  // --- CORE ---
  | 'start' | 'end' | 'user-task' | 'service-task' | 'sub-process' | 'script-task'
  // --- GATEWAYS ---
  | 'exclusive-gateway' | 'parallel-gateway' | 'inclusive-gateway' | 'complex-gateway' | 'event-gateway'
  // --- EVENTS ---
  | 'timer-event' | 'message-event' | 'signal-event' | 'error-event' | 'escalation-event' | 'compensation-event'
  // --- COMMUNICATION ---
  | 'email-send' | 'slack-post' | 'teams-message' | 'sms-twilio' | 'whatsapp-msg' | 'push-notification' | 'sendgrid-email' | 'mailchimp-add'
  // --- DOCUMENTS ---
  | 'pdf-generate' | 'doc-sign' | 'ocr-extract' | 's3-upload' | 'gdrive-save' | 'sharepoint-store' | 'dropbox-save' | 'template-render'
  // --- CRM & SALES ---
  | 'salesforce-create' | 'salesforce-update' | 'hubspot-add' | 'zoho-lead' | 'pipedrive-deal' | 'dynamics-record' | 'zendesk-ticket' | 'intercom-msg'
  // --- DEV TOOLS ---
  | 'jira-issue' | 'github-pr' | 'gitlab-merge' | 'bitbucket-commit' | 'trello-card' | 'asana-task' | 'linear-issue' | 'pagerduty-alert'
  // --- CLOUD INFRA ---
  | 'aws-lambda' | 'azure-func' | 'gcp-function' | 'kubernetes-job' | 'vm-provision' | 'db-provision' | 'dns-update' | 'cdn-purge'
  // --- DATA & INTEGRATION ---
  | 'sql-query' | 'rest-api' | 'graphql-query' | 'soap-call' | 'kafka-publish' | 'rabbit-mq' | 'ftp-upload' | 'csv-parse' | 'xml-transform' | 'json-map'
  // --- AI & ML ---
  | 'ai-text-gen' | 'ai-summarize' | 'ai-sentiment' | 'ai-vision' | 'ai-translate' | 'ai-classify' | 'automl-predict' | 'vector-embed'
  // --- FINANCE ---
  | 'stripe-charge' | 'paypal-payout' | 'quickbooks-invoice' | 'xero-bill' | 'sap-posting' | 'oracle-ledger' | 'expensify-report'
  // --- LOGIC & RULES ---
  | 'business-rule' | 'decision-table' | 'wait-state' | 'terminate-end' | 'loop-container';


export interface ProcessStep {
  id: string;
  name: string;
  type: ProcessStepType;
  description: string;
  role?: string; 
  groupId?: string; 
  requiredSkills?: string[];
  laneId?: string;
  slaDays?: number;
  nextStepIds?: string[];
  position?: { x: number; y: number };
  isCollapsed?: boolean;
  data?: Record<string, any>; // For custom component properties
}

export interface ProcessLink {
  id: string;
  sourceId: string;
  targetId: string;
  label?: string;
  condition?: string;
}

export interface Swimlane {
  id: string;
  name: string;
  height: number;
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
  links?: ProcessLink[];
  lanes?: Swimlane[];
  createdAt: string;
  deployedBy: string;
  version: number;
  isActive: boolean;
  complianceLevel: 'Standard' | 'Strict' | 'Critical';
  history?: { timestamp: string; author: string; message: string }[];
  domainId: string;
}

export interface AuditLog {
  id: string;
  timestamp: string;
  userId: string;
  action: string;
  entityType: 'Process' | 'Task' | 'Instance' | 'System' | 'User' | 'Case' | 'Rule';
  entityId: string;
  details: string;
  severity: 'Info' | 'Warning' | 'Alert';
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated' | 'Suspended';
  activeStepIds: string[];
  startDate: string;
  endDate?: string;
  dueDate?: string;
  variables: Record<string, any>;
  priority: TaskPriority;
  history: TaskHistory[];
  comments: Comment[];
  complianceVerified: boolean;
  domainId: string; 
}

// ---- ADAPTIVE CASE MANAGEMENT ----
export interface CaseStakeholder {
  userId: string;
  role: 'Owner' | 'Consultant' | 'Approver' | 'Auditor';
}
export interface CaseEvent {
  id: string;
  timestamp: string;
  type: 'Manual' | 'System' | 'Task Completion';
  description: string;
  author: string;
}
export interface CasePolicy {
  id: string;
  description: string;
  isEnforced: boolean;
}
export interface Case {
  id: string;
  title: string;
  description: string;
  status: 'Open' | 'In Progress' | 'Pending Review' | 'Resolved' | 'Closed';
  priority: TaskPriority;
  createdAt: string;
  resolvedAt?: string;
  stakeholders: CaseStakeholder[];
  data: Record<string, any>;
  timeline: CaseEvent[];
  policies: CasePolicy[];
  attachments: Attachment[];
  domainId: string;
}

// ---- BUSINESS RULES ENGINE ----
export interface RuleCondition {
  id: string;
  fact: string; // e.g., 'task.priority'
  operator: 'eq' | 'neq' | 'gt' | 'lt' | 'contains';
  value: any;
}

export type Condition = RuleCondition | ConditionGroup;

export interface ConditionGroup {
  id: string;
  type: 'AND' | 'OR';
  children: Condition[];
}

export interface RuleAction {
  type: 'SET_VARIABLE' | 'SEND_NOTIFICATION' | 'ROUTE_TO';
  params: Record<string, any>;
}

export interface BusinessRule {
  id: string;
  name: string;
  description: string;
  conditions: ConditionGroup;
  action: RuleAction;
  priority: number; // For execution order
}

export interface DecisionTable {
  id: string;
  name: string;
  inputs: string[]; // Fact names
  outputs: string[]; // Action param names
  rules: (string | number)[][]; // Matrix of values
}

// ---- ANALYTICS & GOVERNANCE ----
export interface AlertRule {
  id: string;
  name: string;
  condition: RuleCondition;
  notifyUserId: string;
  cooldownMinutes: number;
}


